class ColonyKernel:
    """The control plane for the artificial ecology."""

    def propose_action(self, proposal: ActionProposal) -> GateResult:
        """Pressure -> proposal -> gate -> action."""
        findings = self._falsify(proposal)
        budget_ok = self._ledger.check_budget(proposal)
        return self._gate.evaluate(
            proposal, self._profile(proposal),
            findings, budget_ok,
        )

    def record_outcome(self, result: ConsequenceRecord) -> None:
        """Consequence -> memory -> role -> pressure."""
        self._memory.record(result)
        self._roles.reassign(result.agent_id)
        self._pheromones.deposit(result)

class ActuationGate:
    """The +1/0/-1 permission layer for the Colony Kernel."""

    _GATE_SCORE_EXECUTE = 0.75
    _GATE_SCORE_HOLD = 0.50
    _TRUST_HARD_FLOOR = 0.30

    def evaluate(self, proposal, profile, findings, budget_ok):
        # Hard overrides: SANDBOX always refuses.
        if profile.role == AgentRole.SANDBOX:
            return GateResult(GateDecision.REFUSE, ...)
        # Trust floor: below 0.30, refuse before scoring.
        if profile.trust_score < self._TRUST_HARD_FLOOR:
            return GateResult(GateDecision.REFUSE, ...)
        # CRITICAL falsification -> refuse before scoring.
        if any(f.severity == FalsificationSeverity.CRITICAL
               for f in findings):
            return GateResult(GateDecision.REFUSE, ...)
        # Weighted additive score.
        score = (self._w_budget * budget_ok
                 + self._w_risk * risk_ok
                 + self._w_trust * trust_ok
                 + self._w_complete * completeness)

class PheromoneStore:
    """Typed colony signal layer over TraceField."""

    def deposit(self, signal: ColonySignal) -> None:
        key = f"{signal.type.value}:{signal.location}"
        self._field.deposit(key, signal.strength,
                           source=signal.source,
                           metadata={'decay': signal.decay})

    def pressure_at(self, location: str,
                    signal_type: SignalType) -> float:
        key = f"{signal_type.value}:{location}"
        return self._field.read(key)

    def tick(self) -> None:
        """Evaporate all signals per their configured decay rate."""
        self._field.evaporate()
